// 기본 데이터를 호가 단위로 정렬해 적재 → MSW master/quotes/market 전 핸들러가 동일 기준 sync.
// 현재가·전일종가를 틱 그리드에 맞추고 전일대비/등락률을 거기에 맞춰 재계산. (백엔드 StockMasterJsonAdapter 미러)
export const STOCK_POOL: StockItem[] = raw.map(s => {
  const price     = roundTick(s.price)
  const prevClose = roundTick(s.price - s.prevDiff)
  const prevDiff  = price - prevClose
  const change    = prevClose === 0 ? 0 : Math.round(prevDiff * 1000 / prevClose) / 10
  return {
    rank:          s.rank,
    symbol:        s.symbol,
    name:          s.name,
    market:        s.market,
    price,
    prevDiff,
    change,
    marketCap:     s.marketCap,
    volume:        s.volume,
    tradingAmount: Math.round(s.volume * price / 10_000),
  }
})
